import { useState, useMemo } from "react";
import { Eye, Calendar, ArrowRight, Pin, Trash2, PartyPopper } from "lucide-react";
import { toast } from "sonner";
import { Button } from "@/shadcn/components/ui/button";
import { STORAGE_KEYS } from "@/lib/storageKeys";
import { ROUTES } from "@/lib/routes";
import { queryKeys } from "@/lib/queryKeys";
import { useQuery } from "@tanstack/react-query";
import { format, startOfWeek, endOfWeek, eachDayOfInterval, isSameDay, isAfter, startOfDay } from "date-fns";
import { parseDateOnly } from '@/utils/dateUtils';

import { useAuth } from "@/shared/AuthContext";
import { workScheduleService as accountService } from "@/api/workScheduleService";
import { leaveBalanceService } from "@/api/leaveBalanceService";
import { publicHolidayService } from "@/api/publicHolidayService";
import { useNavigate } from "react-router-dom";

import type { Note } from '@/types/note';

export default function HomePage() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [notes, setNotes] = useState<Note[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.NOTES);
      if (saved) return JSON.parse(saved) as Note[];
    } catch { /* ignore corrupt stored data */ }
    return [{ id: '1', text: 'Welcome to your dashboard! Pin important notes here.' }];
  });
  const [newNote, setNewNote] = useState("");

  const now = new Date();

  // ── Data Fetching ──────────────────────────────────────────────────────────

  // 1. Fetch Current Month Work Schedule
  const { data: schedule, isLoading: scheduleLoading, isError: scheduleError } = useQuery({
    queryKey: queryKeys.workSchedule.myMonth(now.getFullYear(), now.getMonth() + 1),
    queryFn: () => accountService.getWorkSchedule(now.getFullYear(), now.getMonth() + 1),
    enabled: !!user?.id
  });

  // 2. Fetch Leave Balance Ledger
  const { data: ledger = [], isLoading: ledgerLoading, isError: ledgerError } = useQuery({
    queryKey: queryKeys.leaveBalance(user?.id ?? ''),
    queryFn: () => leaveBalanceService.getLedger(user?.id ?? ""),
    enabled: !!user?.id
  });

  // 3. Fetch Public Holidays
  const { data: holidays = [], isLoading: holidaysLoading, isError: holidaysError } = useQuery({
    queryKey: queryKeys.publicHolidays.byYear(now.getFullYear()),
    queryFn: () => publicHolidayService.getAll('Year', now.getFullYear()),
  });

  // ── Derived Data ───────────────────────────────────────────────────────────

  // Calculate Remaining PTO (Sum of ledger entries)
  const remainingPto = useMemo(() => {
    return ledger.reduce((sum, entry) => sum + Number(entry.leaveSize), 0);
  }, [ledger]);

  // Calculate Weekly Work Hours
  const weeklyWorkHours = useMemo(() => {
    if (!schedule?.days) return 0;
    const weekStart = startOfWeek(now, { weekStartsOn: 1 }); // Monday
    const weekEnd = endOfWeek(now, { weekStartsOn: 1 });
    const weekDays = eachDayOfInterval({ start: weekStart, end: weekEnd });

    let hours = 0;
    weekDays.forEach(day => {
      const scheduleDay = schedule.days.find(d => isSameDay(parseDateOnly(d.date) ?? new Date(0), day));
      if (scheduleDay && scheduleDay.shiftType && scheduleDay.shiftType !== 'None') {
        // Assuming standard shift is 8 hours if present
        // In a real app, this would come from a shift definition service
        hours += 8; 
      }
    });
    return hours;
  }, [schedule, now]);

  // Get Current Week Schedule for Display
  const currentWeekDays = useMemo(() => {
    if (!schedule?.days) return [];
    const weekStart = startOfWeek(now, { weekStartsOn: 1 });
    const weekEnd = endOfWeek(now, { weekStartsOn: 1 });
    const weekInterval = eachDayOfInterval({ start: weekStart, end: weekEnd });

    return weekInterval.map(day => {
      const sDay = schedule.days.find(d => isSameDay(parseDateOnly(d.date) ?? new Date(0), day));
      const holiday = holidays.find(h => isSameDay(parseDateOnly(h.holidayOnDate) ?? new Date(0), day));
      return {
        date: day,
        label: format(day, "EEE"),
        dayNum: format(day, "dd"),
        isToday: isSameDay(day, now),
        shift: sDay?.shiftType || (holiday ? "Holiday" : "Off"),
        description: sDay?.workDescription || holiday?.name || (sDay?.shiftType === 'None' || !sDay?.shiftType ? "Weekend / Off" : "Standard Shift"),
        isHoliday: !!holiday,
        holidayName: holiday?.name
      };
    });
  }, [schedule, holidays, now]);

  // Get Upcoming Holidays
  const upcomingHolidays = useMemo(() => {
    const today = startOfDay(now);
    return holidays
      .filter(h => isAfter(parseDateOnly(h.holidayOnDate) ?? new Date(0), today) || isSameDay(parseDateOnly(h.holidayOnDate) ?? new Date(0), today))
      .sort((a, b) => (parseDateOnly(a.holidayOnDate)?.getTime() ?? 0) - (parseDateOnly(b.holidayOnDate)?.getTime() ?? 0))
      .slice(0, 3);
  }, [holidays, now]);

  // ── Local Notes Logic ──────────────────────────────────────────────────────

  const addNote = () => {
    if (!newNote.trim()) return;
    const note: Note = { id: Date.now().toString(), text: newNote.trim() };
    const updated = [note, ...notes];
    setNotes(updated);
    try {
      localStorage.setItem(STORAGE_KEYS.NOTES, JSON.stringify(updated));
    } catch {
      toast.error("Could not save note — browser storage is full.");
    }
    setNewNote("");
  };

  const removeNote = (id: string) => {
    const updated = notes.filter(n => n.id !== id);
    setNotes(updated);
    try {
      localStorage.setItem(STORAGE_KEYS.NOTES, JSON.stringify(updated));
    } catch {
      toast.error("Could not save note — browser storage is full.");
    }
  };

  const isLoading = scheduleLoading || ledgerLoading || holidaysLoading;

  const getTimeGreeting = () => {
    const hour = now.getHours();
    if (hour < 12) return "morning";
    if (hour < 17) return "afternoon";
    return "evening";
  };

  if (isLoading) {
    return (
      <div className="page-wrapper flex flex-col items-center justify-center min-h-100 gap-4">
        <div className="w-12 h-12 border-4 border-primary/10 border-t-primary rounded-full animate-spin" />
        <div className="text-muted-foreground font-semibold text-sm uppercase tracking-widest">Synchronizing Dashboard...</div>
      </div>
    );
  }

  return (
    <div className="page-wrapper space-y-6">

      {(scheduleError || ledgerError || holidaysError) && (
        <p className="text-sm text-destructive">Some data could not be loaded.</p>
      )}

      {/* Welcome Banner */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex flex-col gap-1 relative pl-6">
          <div className="absolute left-0 top-1 bottom-1 w-1.5 bg-primary rounded-full shadow-[0_0_10px_rgba(232,92,13,0.3)]" />
          <h1 className="text-3xl font-black text-foreground tracking-tight leading-tight">
            Good {getTimeGreeting()}, <span className="text-primary">{user?.fullName?.split(' ')[0] || 'Admin'}</span>.
          </h1>
          <p className="text-sm font-bold text-muted-foreground uppercase tracking-[0.2em]">
            {format(now, 'EEEE, MMMM do, yyyy')}
          </p>
        </div>
        <div className="flex gap-4">
          <div className="glass-card rounded-2xl flex flex-col items-center min-w-37.5 p-4 group hover:-translate-y-1 transition-all duration-500">
            <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest mb-1">Weekly Commitment</p>
            <p className="text-xl font-black text-foreground">{weeklyWorkHours} <span className="text-xs font-bold text-muted-foreground">HRS</span></p>
          </div>
          <div className="glass-card rounded-2xl flex flex-col items-center min-w-37.5 p-4 group hover:-translate-y-1 transition-all duration-500">
            <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest mb-1">Available Leave</p>
            <p className="text-xl font-black text-foreground">{remainingPto} <span className="text-xs font-bold text-muted-foreground">DAYS</span></p>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-5">

        {/* Main Content */}
        <section className="col-span-1 lg:col-span-8 space-y-5">

          {/* Weekly Schedule */}
          <div className="section-card overflow-hidden mb-0! shadow-sm border border-border">
            <div className="section-card-header bg-muted/30">
              <div className="flex items-center gap-2">
                <div className="p-2 bg-primary/10 rounded-lg text-primary">
                  <Calendar size={14} />
                </div>
                <div>
                  <h3 className="section-card-title">This Week's Schedule</h3>
                  <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Plan and track your assignments</p>
                </div>
              </div>
              <button 
                onClick={() => navigate(ROUTES.MY_WORK_SCHEDULE)}
                className="text-xs font-bold text-primary hover:opacity-80 flex items-center gap-1 transition-all uppercase tracking-tight"
              >
                Manage <ArrowRight size={10} />
              </button>
            </div>

            <div className="divide-y divide-border">
              {currentWeekDays.map((d) => (
                <div
                  key={String(d.date)}
                  className={`flex flex-col sm:flex-row sm:items-center justify-between px-5 py-4 transition-all gap-3
                    ${d.isToday ? "bg-primary/5 border-l-4 border-primary" : "hover:bg-muted/30"}
                    ${d.isHoliday ? "bg-amber-50/30 dark:bg-amber-950/10" : ""}
                  `}
                >
                  <div className="flex items-center space-x-6">
                    <div className="text-center w-10 shrink-0">
                      <p className={`text-[10px] font-black uppercase tracking-tighter ${d.isToday ? "text-primary" : "text-muted-foreground"}`}>{d.label}</p>
                      <p className={`text-xl font-black ${d.isToday ? "text-primary" : "text-foreground"}`}>{d.dayNum}</p>
                    </div>
                    <div className="h-10 w-px bg-border hidden sm:block" />
                    <div>
                      <div className="flex items-center gap-2">
                        <p className={`text-sm font-bold ${d.isToday ? "text-foreground" : "text-foreground"}`}>
                          {d.description || ""}
                        </p>
                        {d.isToday && <span className="px-2 py-0.5 bg-primary text-primary-foreground text-[9px] font-black rounded-full uppercase tracking-widest shadow-lg shadow-primary/30">Today</span>}
                        {d.isHoliday && <span className="px-2 py-0.5 bg-amber-100 dark:bg-amber-950/40 text-amber-700 dark:text-amber-400 text-[9px] font-black rounded-full uppercase tracking-widest flex items-center gap-1 border border-amber-200 dark:border-amber-800"><PartyPopper size={10} /> Holiday</span>}
                      </div>
                      <p className="text-[11px] font-medium text-muted-foreground mt-0.5">
                        {d.isHoliday ? "Company Holiday - No Shift" : (d.shift === 'Off' ? "Rest Day" : `Shift: ${d.shift}`)}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={() => navigate(ROUTES.MY_WORK_SCHEDULE)}
                    className={`h-10 w-10 flex items-center justify-center rounded-2xl border transition-all duration-300 group
                      ${d.isToday
                        ? "bg-primary text-primary-foreground border-primary shadow-lg shadow-primary/20 hover:scale-110 active:scale-95"
                        : "bg-card border-border text-muted-foreground hover:border-primary hover:text-primary hover:shadow-md hover:-translate-y-0.5 active:scale-95"
                      }
                    `}
                  >
                    <Eye size={18} strokeWidth={2.5} className="group-hover:scale-110 transition-transform" />
                  </button>
                </div>
              ))}
            </div>
          </div>

          {/* Pinned Notes */}
          <div className="section-card p-6 mb-0! shadow-sm border border-border">
            <div className="flex items-center gap-2 mb-6">
              <div className="p-2 bg-primary/10 rounded-lg text-primary">
                <Pin size={14} />
              </div>
              <div>
                <h3 className="section-card-title">Quick Notes</h3>
                <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Jot down your thoughts</p>
              </div>
            </div>
 
            <div className="flex gap-2 mb-6">
              <input
                type="text"
                value={newNote}
                onChange={(e) => setNewNote(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && addNote()}
                placeholder="Jot down a quick note or reminder..."
                className="flex-1 rounded-xl bg-muted/50 border border-border px-3 py-2 text-sm font-medium text-foreground outline-none focus:bg-background focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all"
              />
              <Button className="rounded-xl px-6" onClick={addNote}>Pin</Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {notes.length === 0 ? (
                <div className="col-span-full py-8 text-center bg-muted/30 rounded-2xl border border-dashed border-border">
                  <p className="text-muted-foreground text-sm font-medium">No pinned notes yet.</p>
                </div>
              ) : (
                notes.map(note => (
                  <div key={note.id} className="group bg-amber-50/50 dark:bg-amber-950/20 border border-amber-100/50 dark:border-amber-800/30 p-5 rounded-2xl flex justify-between items-start gap-3 hover:shadow-md transition-all">
                    <p className="text-sm text-amber-900 dark:text-amber-200 leading-relaxed font-semibold whitespace-pre-wrap">{note.text}</p>
                    <button
                      onClick={() => removeNote(note.id)}
                      className="text-amber-200 dark:text-amber-700 hover:text-rose-500 transition-colors shrink-0 opacity-0 group-hover:opacity-100"
                      title="Remove note"
                    >
                      <Trash2 size={12} />
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </section>

        {/* Sidebar Widgets */}
        <aside className="col-span-1 lg:col-span-4 space-y-6">
 
           {/* Upcoming Holidays */}
           <div className="section-card p-7 shadow-sm border border-border">
             <div className="flex items-center justify-between mb-8">
               <div>
                 <h3 className="section-card-title text-base!">Calendar Holidays</h3>
                 <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-wider">Upcoming company breaks</p>
               </div>
               <div className="p-2 bg-primary/10 border border-primary/20 rounded-lg text-primary">
                 <Calendar size={14} />
               </div>
             </div>
             <div className="space-y-5">
               {upcomingHolidays.length === 0 ? (
                 <p className="text-sm text-muted-foreground text-center py-4 italic">No upcoming holidays found.</p>
               ) : (
                 upcomingHolidays.map((h) => (
                   <div key={h.holidayOnDate} className="flex items-start space-x-5 group">
                     <div className="bg-muted/50 border border-border rounded-xl p-2.5 text-center min-w-14 group-hover:bg-primary/5 group-hover:border-primary/20 transition-all shadow-sm">
                       <p className="text-[10px] font-black text-muted-foreground group-hover:text-primary uppercase tracking-widest">{format(parseDateOnly(h.holidayOnDate) ?? new Date(0), "MMM")}</p>
                       <p className="text-xl font-black text-foreground leading-tight">{format(parseDateOnly(h.holidayOnDate) ?? new Date(0), "dd")}</p>
                     </div>
                     <div className="pt-1.5">
                       <p className="text-sm font-black text-foreground transition-colors">{h.name}</p>
                       <p className="text-[11px] font-bold text-muted-foreground uppercase tracking-widest mt-0.5">{h.description || "Public Holiday"}</p>
                     </div>
                   </div>
                 ))
               )}
             </div>
             <button
               onClick={() => navigate(ROUTES.PUBLIC_HOLIDAYS)}
               className="w-full mt-8 py-3.5 bg-muted border border-border text-muted-foreground text-[10px] font-black uppercase tracking-[0.2em] rounded-xl hover:bg-card hover:border-border hover:text-foreground transition-all flex items-center justify-center gap-2 group shadow-sm"
             >
               <span>Full Calendar</span>
               <ArrowRight size={10} className="group-hover:translate-x-1 transition-transform" />
             </button>
           </div>
 
           {/* Team Update */}
           <div className="section-card p-8 shadow-xl shadow-primary/20 border border-primary/10 bg-linear-to-br from-primary to-primary/40 text-primary-foreground relative overflow-hidden">
             <div className="absolute top-0 right-0 -mr-8 -mt-8 w-32 h-32 bg-white/10 rounded-full blur-3xl" />
             <div className="relative z-10">
                <div className="flex items-center gap-2 mb-4">
                  <div className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
                  <p className="text-[10px] font-black uppercase tracking-[0.3em] opacity-90">Harmony Update</p>
                </div>
                <p className="text-sm font-medium leading-relaxed mb-6 opacity-90">
                  Welcome to the new Harmony dashboard! You can now track your work hours, PTO balance, and weekly schedule in real-time.
                </p>
                <button 
                  onClick={() => navigate(ROUTES.MY_PROFILE)}
                  className="inline-flex text-[10px] font-black uppercase tracking-[0.2em] bg-primary-foreground text-primary px-6 py-3 rounded-xl items-center gap-2.5 transition-all hover:bg-primary-foreground/90 hover:scale-105 active:scale-95"
                >
                  <span>View Profile</span>
                  <ArrowRight size={10} />
                </button>
             </div>
           </div>

        </aside>
      </div>
    </div>
  );
}
